import React, { useState } from "react";
import axios from "axios";

function StockDetails() {
  const [symbol, setSymbol] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const handleFetch = async () => {
    try {
      setError("");
      const res = await axios.get(`http://localhost:3000/api/stock/${symbol}`);
      setData(res.data);
    } catch (err) {
      setError("Failed to fetch data.");
      console.error(err);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>US Stock Details (Alpha Vantage)</h2>

      <input
        type="text"
        placeholder="Enter symbol, e.g. AAPL"
        value={symbol}
        onChange={(e) => setSymbol(e.target.value)}
      />
      <button onClick={handleFetch}>Fetch</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <div>
          <h3>{data.overview.Name} ({data.overview.Symbol})</h3>
          <p>{data.overview.Description}</p>

          <h4>Market Info:</h4>
          <ul>
            <li>Sector: {data.overview.Sector}</li>
            <li>Industry: {data.overview.Industry}</li>
            <li>Market Cap: {data.overview.MarketCapitalization}</li>
            <li>PE Ratio: {data.overview.PERatio}</li>
          </ul>

          <h4>Latest Daily Price:</h4>
          {data.dailyPrices && (
            <div>
              {(() => {
                const latestDate = Object.keys(data.dailyPrices)[0];
                const priceInfo = data.dailyPrices[latestDate];
                return (
                  <ul>
                    <li>Date: {latestDate}</li>
                    <li>Open: {priceInfo["1. open"]}</li>
                    <li>High: {priceInfo["2. high"]}</li>
                    <li>Low: {priceInfo["3. low"]}</li>
                    <li>Close: {priceInfo["4. close"]}</li>
                  </ul>
                );
              })()}
            </div>
          )}

          <h4>10-Day SMA:</h4>
          {data.sma && (
            <ul>
              {Object.entries(data.sma).map(([date, smaData]) => (
                <li key={date}>
                  {date}: {smaData.SMA}
                </li>
              ))}
            </ul>
          )}

          <h4>Earnings:</h4>
          <table border="1" cellPadding="5">
            <thead>
              <tr>
                <th>Fiscal Date</th>
                <th>Reported EPS</th>
              </tr>
            </thead>
            <tbody>
              {data.earnings?.map((item, idx) => (
                <tr key={idx}>
                  <td>{item.fiscalDateEnding}</td>
                  <td>{item.reportedEPS}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default StockDetails;
